// ──────────────────────────────────────────────
// VALIDATE & ENRICH incoming lead payload
// ──────────────────────────────────────────────
const raw = $input.first().json;
const body = raw.body || raw;

const lead = {
  name:    body.name    || body.full_name  || 'Unknown',
  email:   body.email   || null,
  phone:   body.phone   || body.mobile     || null,
  source:  body.source  || body.utm_source || 'website',
  message: body.message || body.notes      || body.inquiry || '',
  vehicle_interest: body.vehicle_interest || body.vehicle || null,
  budget_min: parseFloat(body.budget_min) || null,
  budget_max: parseFloat(body.budget_max) || null,
  timeline: body.timeline || null,
  has_trade_in: body.has_trade_in === true || body.has_trade_in === 'true',
  received_at: new Date().toISOString()
};

// Basic validation
if (!lead.name || lead.name === 'Unknown') {
  if (!lead.email && !lead.phone) {
    throw new Error('Lead must have at least a name, email, or phone');
  }
}

return [{ json: lead }];

