// ──────────────────────────────────────────────
// PARSE AI SCORING RESPONSE + MERGE WITH LEAD
// ──────────────────────────────────────────────
const aiResponse = $input.first().json;
const lead = $node['Validate & Enrich Input'].json;

let scoring;
try {
  const content = aiResponse.choices[0].message.content;
  const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  scoring = JSON.parse(cleaned);
} catch (e) {
  // FALLBACK: If AI fails, default to WARM (safe middle ground)
  scoring = {
    score: 55,
    priority: 'WARM',
    intent: 'AI scoring failed — manual review needed',
    buy_probability: 0.5,
    recommended_action: 'Manually review this lead',
    reasoning: 'AI parse error: ' + e.message
  };
}

// Merge lead data with AI scoring
const enrichedLead = {
  ...lead,
  ai_score: scoring.score,
  ai_priority: scoring.priority,
  ai_intent: scoring.intent,
  ai_probability: scoring.buy_probability,
  status: 'new',
  recommended_action: scoring.recommended_action,
  scoring_reasoning: scoring.reasoning,
  scored_at: new Date().toISOString()
};

return [{ json: enrichedLead }];

// ──────────────────────────────────────────────
// MERGE: Get lead ID from Supabase + scoring data
// ──────────────────────────────────────────────
const supabaseResponse = $input.first().json;
const scoredLead = $node['Parse AI Decision'].json;

// Supabase returns array — get the first item
const savedLead = Array.isArray(supabaseResponse) ? supabaseResponse[0] : supabaseResponse;

return [{
  json: {
    ...scoredLead,
    lead_id: savedLead?.id || 'unknown',
    supabase_saved: !!savedLead?.id
  }
}];

// ──────────────────────────────────────────────
// HOT LEAD: Build Slack alert + prep for downstream
// ──────────────────────────────────────────────
const lead = $input.first().json;

const slackPayload = {
  channel: 'C0BJ5PLTPDJ',
  text: `🔥 *HOT LEAD ALERT* — Score: ${lead.ai_score}/100`,
  blocks: [
    {
      type: 'header',
      text: { type: 'plain_text', text: '🔥 HOT LEAD — Immediate Action Required' }
    },
    {
      type: 'section',
      fields: [
        { type: 'mrkdwn', text: `*Name:*\n${lead.name}` },
        { type: 'mrkdwn', text: `*Score:*\n${lead.ai_score}/100` },
        { type: 'mrkdwn', text: `*Source:*\n${lead.source}` },
        { type: 'mrkdwn', text: `*Vehicle:*\n${lead.vehicle_interest || 'Not specified'}` }
      ]
    },
    {
      type: 'section',
      text: { type: 'mrkdwn', text: `*AI Intent:* ${lead.ai_intent}\n*Action:* ${lead.recommended_action}` }
    },
    {
      type: 'context',
      elements: [
        { type: 'mrkdwn', text: `Lead ID: ${lead.lead_id} | ${lead.scored_at}` }
      ]
    }
  ]
};

return [{ json: { ...lead, slackPayload } }];

// ──────────────────────────────────────────────
// WARM LEAD: Prep for WhatsApp outreach + drip
// ──────────────────────────────────────────────
const lead = $input.first().json;

return [{
  json: {
    ...lead,
    drip_stage: 'warm_initial',
    next_action: 'whatsapp_outreach',
    message_template: `Hi ${lead.name}, thank you for your interest in ${lead.vehicle_interest || 'our vehicles'}! I'm from NEXUS OS premium dealership. Would you like to schedule a viewing?`
  }
}];

// ──────────────────────────────────────────────
// COLD LEAD: Enroll in automated drip campaign
// ──────────────────────────────────────────────
const lead = $input.first().json;

return [{
  json: {
    ...lead,
    drip_stage: 'cold_day0',
    enrolled_at: new Date().toISOString(),
    next_action: 'marketing_drip_7day'
  }
}];
